FROM jsonb_to_recordset('[{"id": "cap-104-chinese-001", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "小敬搬新家，阿嬌欲送禮金表達祝賀之意。下列題辭，何者最適合寫在賀儀封套上？", "options": ["近悅遠來", "造福桑梓", "宜室宜家", "喬遷之喜"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 1, "raw_text": "1.   小敬搬新家，阿嬌欲送禮金表達祝賀之意。下列題辭，何者最適合寫在賀儀封套上？\n     (A)近悅遠來   (B)造福桑梓   (C)宜室宜家   (D)喬遷之喜\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-002", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "下列文句，何者文意最為通暢？", "options": ["因為你不去，我還是要去", "他年紀既然小，膽子卻不小", "雖然這是第一次，所以做得很好", "她的作品不是不好，而是缺少創意"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 2, "raw_text": "2.   下列文句，何者文意最為通暢？\n     (A)因為你不去，我還是要去\n     (B)他年紀既然小，膽子卻不小\n     (C)雖然這是第一次，所以做得很好\n     (D)她的作品不是不好，而是缺少創意\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-003", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "「當部分亞洲國家為了生產足夠的稻米而焦頭爛額之際，泰國稻米的產量卻多到一\n年出口九百萬噸，是全世界最大稻米輸出國。泰國成為世界米倉的原因是：民營企\n業非常有效率，擁有大量平坦肥沃的三角洲和充沛的水源，再加上政府機關支\n持民間銀行貸款給小農購買種子、肥料。以上種種，使泰國在米糧危機中占盡\n利益。」這段文字的主旨為下列何者？", "options": ["泰國米質提升的技術", "泰國稻米盛產的原因", "泰國稻米行銷的方式", "泰國復興米業的計畫"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 3, "raw_text": "3.   「當部分亞洲國家為了生產足夠的稻米而焦頭爛額之際，泰國稻米的產量卻多到一\n     年出口九百萬噸，是全世界最大稻米輸出國。泰國成為世界米倉的原因是：民營企\n     業非常有效率，擁有大量平坦肥沃的三角洲和充沛的水源，再加上政府機關支\n     持民間銀行貸款給小農購買種子、肥料。以上種種，使泰國在米糧危機中占盡\n     利益。」這段文字的主旨為下列何者？\n     (A)泰國米質提升的技術     (B)泰國稻米盛產的原因\n     (C)泰國稻米行銷的方式     (D)泰國復興米業的計畫\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-004", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "下列詞語「」中的字音，何組相同？", "options": ["風聲鶴「唳」／暴「戾」之氣", "「揖」讓而升／查「緝」走私", "「擣」米去糠／陶「鑄」品行", "再三叮「嚀」／滿地泥「濘」"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 4, "raw_text": "4.   下列詞語「」中的字音，何組相同？\n     (A)風聲鶴「唳」／暴「戾」之氣\n     (B)「揖」讓而升／查「緝」走私\n     (C)「擣」米去糠／陶「鑄」品行\n     (D)再三叮「嚀」／滿地泥「濘」\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-005", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "「時然後言，人不厭其言。」這句話的涵義，與下列何者最接近？", "options": ["沉默是金，可免禍從口出", "善傾聽者，聞言必加審查", "適時發言，方為人所接受", "經常練習，言語方能動聽"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 5, "raw_text": "5.   「時然後言，人不厭其言。」這句話的涵義，與下列何者最接近？\n     (A)沉默是金，可免禍從口出  (B)善傾聽者，聞言必加審查\n     (C)適時發言，方為人所接受  (D)經常練習，言語方能動聽\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-006", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "下列詞語，何者沒有錯別字？", "options": ["營私舞幣", "武功祕笈", "試目以待", "時代先軀"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 6, "raw_text": "6.   下列詞語，何者沒有錯別字？\n     (A)營私舞幣   (B)武功祕笈       (C)試目以待     (D)時代先軀\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-007", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "下列選項「」中的疊字，何者是用來描摹聲音的狀聲詞？", "options": ["「嘖嘖」稱奇的老師", "「侃侃」而談的官員", "「滔滔」不絕的名嘴", "「聲聲」叮嚀的母親"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 7, "raw_text": "7.   下列選項「」中的疊字，何者是用來描摹聲音的狀聲詞？\n     (A)「嘖嘖」稱奇的老師    (B)「侃侃」而談的官員\n     (C)「滔滔」不絕的名嘴    (D)「聲聲」叮嚀的母親\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-008", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "小王和小林第一次碰面，下列寒暄的語句，何者最不適合出現在他們的對話中？", "options": ["久違了，很高興見到你", "真是聞名不如見面啊", "久仰了，請多多指教", "幸會，幸會"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 8, "raw_text": "8.   小王和小林第一次碰面，下列寒暄的語句，何者最不適合出現在他們的對話中？\n     (A)久違了，很高興見到你    (B)真是聞名不如見面啊\n     (C)久仰了，請多多指教     (D)幸會，幸會\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-009", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "「物產豐富」中的「物產」是本句的主語。下列各選項「」中的語詞，何者不做\n主語使用？", "options": ["「四海」昇平", "「群魔」亂舞", "「氣焰」囂張", "「百年」樹人"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 9, "raw_text": "9.   「物產豐富」中的「物產」是本句的主語。下列各選項「」中的語詞，何者不做\n     主語使用？\n     (A)「四海」昇平       (B)「群魔」亂舞\n     (C)「氣焰」囂張       (D)「百年」樹人\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-010", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "「豆，古代食器，用以盛肉醬一類食物，器淺如盤，下有一足，大多數有蓋。春秋\n以後，豆增多，側有兩環，下具高足。到戰國時期，器腹變深，蓋上有捉手，\n可以仰置。」根據這段敘述，下列何者最可能是戰國時期的「豆」器？", "options": ["", "", "", ""], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": ["option_incomplete", "option_image"], "parse_confidence": 0.4, "original_question_number": 10, "raw_text": "10. 「豆，古代食器，用以盛肉醬一類食物，器淺如盤，下有一足，大多數有蓋。春秋\n    以後，豆增多，側有兩環，下具高足。到戰國時期，器腹變深，蓋上有捉手，\n    可以仰置。」根據這段敘述，下列何者最可能是戰國時期的「豆」器？\n    (A)      (B)      (C)      (D)\n\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-011", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "「有農夫種茄不活，求計於農務司，司吏曰：『此不難，每茄根下埋一文即活。』\n問其何故，答曰：『有錢者生，無錢者死。』」這段文字主要在揭露世間哪一種\n醜態？", "options": ["貪官好賄，索求無度", "官商勾結，欺瞞大眾", "不務正道，盡信偏方", "鑽營旁門，好走捷徑"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 11, "raw_text": "11. 「有農夫種茄不活，求計於農務司，司吏曰：『此不難，每茄根下埋一文即活。』\n    問其何故，答曰：『有錢者生，無錢者死。』」這段文字主要在揭露世間哪一種\n    醜態？\n    (A)貪官好賄，索求無度\n    (B)官商勾結，欺瞞大眾\n    (C)不務正道，盡信偏方\n    (D)鑽營旁門，好走捷徑\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-012", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "下列詩句，何者與「亂花漸欲迷人眼，淺草纔能沒馬蹄」所描述的季節相同？", "options": ["金風扇微涼，遠煙凝翠晶", "樓倚霜樹外，鏡天無一毫", "隨風柳絮輕，映日杏花明", "黃葉覆溪橋，荒村惟古木"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 12, "raw_text": "12. 下列詩句，何者與「亂花漸欲迷人眼，淺草纔能沒馬蹄」所描述的季節相同？\n    (A)金風扇微涼，遠煙凝翠晶\n    (B)樓倚霜樹外，鏡天無一毫\n    (C)隨風柳絮輕，映日杏花明\n    (D)黃葉覆溪橋，荒村惟古木\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-013", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "一家書店的外牆寫著：「在我看來，托爾斯泰和杜思妥也夫斯基比隔壁鄰居更真\n實。更奇怪的是，早在我尚未出生以前，杜思妥也夫斯基就在一本叫做《白痴》\n的書中，寫出了我的人生故事。」根據這段文字，下列推論何者最恰當？", "options": ["作者過於耽溺書本，鄰居鮮少與他往來", "作者的人生經歷被杜思妥也夫斯基寫入書中", "從托氏與杜氏的書中，作者看到了真實的人生", "閱讀托氏與杜氏的作品，作者有知音難遇的感慨"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 13, "raw_text": "13. 一家書店的外牆寫著：「在我看來，托爾斯泰和杜思妥也夫斯基比隔壁鄰居更真\n    實。更奇怪的是，早在我尚未出生以前，杜思妥也夫斯基就在一本叫做《白痴》\n    的書中，寫出了我的人生故事。」根據這段文字，下列推論何者最恰當？\n    (A)作者過於耽溺書本，鄰居鮮少與他往來\n    (B)作者的人生經歷被杜思妥也夫斯基寫入書中\n    (C)從托氏與杜氏的書中，作者看到了真實的人生\n    (D)閱讀托氏與杜氏的作品，作者有知音難遇的感慨\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-014", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "「我只希望，我們的距離□我和所有野鳥的距離，永遠是這樣接近。」句中空格\n處填入下列哪一種標點符號最恰當？", "options": ["；", "！", "……", "――"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 14, "raw_text": "14. 「我只希望，我們的距離□我和所有野鳥的距離，永遠是這樣接近。」句中空格\n    處填入下列哪一種標點符號最恰當？\n    (A)；   (B)！   (C)……   (D) ――\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
